import{showNotification}from './lib/utils.js';import{apiClient}from './lib/apiClient.js';document.addEventListener('DOMContentLoaded',()=>{setupErrorHandling();setupKeyboardShortcuts();setupAutoSaveIndicator();showWelcomeMessage();setupResumeImport();initOptimizationLevelSelector();initAuthUI();});async function initAuthUI(){try{const{authModal}=await import('./components/authModal.js');authModal.updateUI();window.addEventListener('auth-change',()=>{authModal.updateUI();});}catch (error){}}function setupKeyboardShortcuts(){document.addEventListener('keydown',(e)=>{if ((e.ctrlKey||e.metaKey)&&e.key==='s'){e.preventDefault();store.save();showNotification('已保存到本地','success');}if ((e.ctrlKey||e.metaKey)&&e.key==='p'){e.preventDefault();pdfGenerator.preview();}if (e.key==='Escape'){aiOptimizer.closePanel();}});}function setupAutoSaveIndicator(){const indicator=document.createElement('div');indicator.id='autoSaveIndicator';indicator.className='fixed bottom-4 left-4 px-3 py-1.5 bg-gray-800 text-gray-400 text-xs rounded-lg opacity-0 transition-opacity';indicator.innerHTML='<i class="fas fa-check-circle text-green-500 mr-1"></i>已自动保存';document.body.appendChild(indicator);let saveTimeout;store.subscribe(()=>{indicator.style.opacity='1';clearTimeout(saveTimeout);saveTimeout=setTimeout(()=>{indicator.style.opacity='0';},2000);});}function showWelcomeMessage(){const hasVisited=localStorage.getItem('resumeOptimizerVisited');if (!hasVisited){setTimeout(()=>{showNotification('欢迎使用 AI 简历优化工具！填写左侧表单，右侧实时预览','info');localStorage.setItem('resumeOptimizerVisited','true');},1000);}}let importInitialized=false;function setupResumeImport(){if (importInitialized) return;let attempts=0;const maxAttempts=30;const checkAndSetup=()=>{const importBtn=document.getElementById('importResumeBtn');if (!importBtn){attempts++;if (attempts<maxAttempts){setTimeout(checkAndSetup,100);}return;}importBtn.addEventListener('click',()=>{openResumeImport();});importInitialized=true;};checkAndSetup();}let importListenerAdded=false;function openResumeImport(){import('./components/importResume.js') .then(({importResume})=>{importResume.init('importResumeContainer');importResume.open();if (!importListenerAdded){document.addEventListener('resumeImportComplete',handleResumeImportComplete);importListenerAdded=true;}}) .catch(error=>{showNotification('简历导入功能加载失败，请刷新页面重试','error');});}function handleResumeImportComplete(event){const importedData=event.detail;updateResumeFormWithImportedData(importedData);showNotification('简历数据已成功导入！','success');}function initOptimizationLevelSelector(){let attempts=0;const maxAttempts=30;const checkAndInit=()=>{attempts++;if (window.aiOptimizer&&aiOptimizer._renderOptimizationLevels){const savedLevel=localStorage.getItem('optimization_level')||'medium';aiOptimizer.currentLevel=savedLevel;aiOptimizer._renderOptimizationLevels();}else if (attempts<maxAttempts){setTimeout(checkAndInit,100);}};checkAndInit();}function updateResumeFormWithImportedData(data){if (!window.resumeForm||!window.store){return;}try{if (data.profile){const profileFields={profileName:data.profile.name,profileTitle:data.profile.title||'求职者',profileEmail:data.profile.email,profilePhone:data.profile.phone,profileLocation:data.profile.location,profileSummary:data.profile.summary};Object.entries(profileFields).forEach(([fieldId,value])=>{const field=document.getElementById(fieldId);if (field&&value){field.value=value;field.dispatchEvent(new Event('input',{bubbles:true}));}});}if (data.experience&&data.experience.length>0){const experienceContainer=document.querySelector('[data-section="experience"]');if (experienceContainer){experienceContainer.innerHTML='';}data.experience.forEach((exp,index)=>{addExperienceItem(exp);});}if (data.education&&data.education.length>0){const educationContainer=document.querySelector('[data-section="education"]');if (educationContainer){educationContainer.innerHTML='';}data.education.forEach((edu,index)=>{addEducationItem(edu);});}if (data.skills&&data.skills.length>0){const skillsInput=document.getElementById('skillsInput');if (skillsInput){skillsInput.value=data.skills.join(',');skillsInput.dispatchEvent(new Event('input',{bubbles:true}));}}setTimeout(()=>{if (window.store&&typeof window.store.save==='function'){window.store.save();}},100);}catch (error){showNotification('导入数据更新表单时出错','error');}}function addExperienceItem(experience){if (!window.resumeForm||typeof window.resumeForm.addExperience!=='function'){return;}try{const parseDate=(dateStr)=>{if (!dateStr||dateStr.trim()==='') return '';let d=dateStr.trim();if (d==='至今'||d==='现在'||d.toLowerCase()==='present') return d;d=d.replace(/年/g,'.').replace(/月/g,'');const m=d.match(/^(\d{4})[.\-/](\d{1,2})$/);if (m) return `${m[1]}.${m[2].padStart(2,'0')}`;return d;};let startDate=parseDate(experience.startDate);let endDate=parseDate(experience.endDate);if (!startDate&&!endDate&&experience.period){const p=experience.period;const parts=p.split(/\s*[-–—至到]\s*/);if (parts.length>=2){startDate=parseDate(parts[0]);endDate=parseDate(parts.slice(1).join('-'));}else if (parts.length===1){startDate=parseDate(parts[0]);endDate='至今';}}const expData={company:experience.company||'',position:experience.position||experience.title||'',startDate:startDate,endDate:endDate||'至今',description:experience.description||''};window.resumeForm.addExperience(expData);}catch (error){}}function addEducationItem(education){if (!window.resumeForm||typeof window.resumeForm.addEducation!=='function'){return;}try{const parseDate=(dateStr)=>{if (!dateStr||dateStr.trim()==='') return '';let d=dateStr.trim();d=d.replace(/年/g,'.').replace(/月/g,'');const m=d.match(/^(\d{4})[.\-/](\d{1,2})$/);if (m) return `${m[1]}.${m[2].padStart(2,'0')}`;return d;};let graduationDate='';if (education.endDate){graduationDate=parseDate(education.endDate);}else if (education.period){const parts=education.period.split(/\s*[-–—至到]\s*/);graduationDate=parts.length>=2 ? parseDate(parts[parts.length-1]):parseDate(parts[0]);}else if (education.graduationDate){graduationDate=parseDate(education.graduationDate);}const eduData={school:education.school||'',degree:education.degree||'',major:education.major||education.field||'',graduationDate:graduationDate,description:education.description||''};window.resumeForm.addEducation(eduData);}catch (error){}}function setupErrorHandling(){window.addEventListener('unhandledrejection',event=>{showNotification('操作出现错误，请稍后重试','error');});window.addEventListener('error',event=>{if (event.message&&event.message.includes('chrome-extension')){return;}showNotification('页面出现错误，请刷新重试','error');});}